// 读取当前文档的所有段落内容，分析标题结构
var doc = Application.ActiveDocument;
var paragraphs = doc.Paragraphs;
var result = [];
var titleCount = 0;

for (var i = 1; i <= paragraphs.Count; i++) {
    var para = paragraphs.Item(i);
    var text = para.Range.Text.trim();
    var style = para.Style.NameLocal;

    // 检查是否是标题样式
    if (style.indexOf("标题") !== -1 || style.indexOf("Heading") !== -1) {
        titleCount++;
        result.push({
            index: i,
            text: text,
            style: style,
            level: getTitleLevel(style)
        });
    }
}

// 判断标题级别
function getTitleLevel(styleName) {
    if (styleName.indexOf("标题 1") !== -1 || styleName.indexOf("Heading 1") !== -1) return 1;
    if (styleName.indexOf("标题 2") !== -1 || styleName.indexOf("Heading 2") !== -1) return 2;
    if (styleName.indexOf("标题 3") !== -1 || styleName.indexOf("Heading 3") !== -1) return 3;
    if (styleName.indexOf("标题 4") !== -1 || styleName.indexOf("Heading 4") !== -1) return 4;
    if (styleName.indexOf("标题 5") !== -1 || styleName.indexOf("Heading 5") !== -1) return 5;
    if (styleName.indexOf("标题 6") !== -1 || styleName.indexOf("Heading 6") !== -1) return 6;
    if (styleName.indexOf("标题 7") !== -1 || styleName.indexOf("Heading 7") !== -1) return 7;
    if (styleName.indexOf("标题 8") !== -1 || styleName.indexOf("Heading 8") !== -1) return 8;
    if (styleName.indexOf("标题 9") !== -1 || styleName.indexOf("Heading 9") !== -1) return 9;
    return 0;
}

return {
    totalParagraphs: paragraphs.Count,
    titleCount: titleCount,
    titles: result,
    documentName: doc.Name
};

// 检查文档中可能作为标题的文本（如数字编号开头的段落）
var doc = Application.ActiveDocument;
var paragraphs = doc.Paragraphs;
var potentialTitles = [];
var numberedPatterns = [];

for (var i = 1; i <= paragraphs.Count; i++) {
    var para = paragraphs.Item(i);
    var text = para.Range.Text.trim();

    // 检查常见的标题编号模式
    if (text.length > 0) {
        // 检查数字编号模式：如 "1. ", "1.1 ", "1.1.1 " 等
        var numberMatch = text.match(/^(\d+(\.\d+)*\.?\s+)/);
        // 检查中文编号模式：如 "一、", "（一）", "1．" 等
        var chineseMatch = text.match(/^([一二三四五六七八九十]+[、．]|（[一二三四五六七八九十]+）|\d+[．．])\s*/);

        if (numberMatch || chineseMatch) {
            potentialTitles.push({
                index: i,
                text: text,
                originalText: text,
                pattern: numberMatch ? numberMatch[1] : chineseMatch[0]
            });
        }

        // 检查是否有明显的章节标题关键词
        var keywords = ["章", "节", "条", "款", "项", "目", "附录", "附件", "参考文献"];
        for (var j = 0; j < keywords.length; j++) {
            if (text.indexOf(keywords[j]) !== -1 && text.length < 100) {
                numberedPatterns.push({
                    index: i,
                    text: text,
                    keyword: keywords[j]
                });
                break;
            }
        }
    }
}

return {
    potentialTitles: potentialTitles,
    numberedPatterns: numberedPatterns,
    sampleTexts: potentialTitles.length > 0 ? potentialTitles.slice(0, 5) : []
};

