for (var i = 1; i <= paragraphs.Count; i++) {
    var para = paragraphs.Item(i);
    var text = para.Range.Text.trim();

    // 检查标题编号模式
    if (text.length > 0) {
        // 匹配数字编号模式：如 "1. ", "1.1 ", "1.1.1 " 等
        var numberMatch = text.match(/^(\d+(\.\d+)*\.?\s+)/);
        // 匹配中文章节模式：如 "第一章", "第二章" 等
        var chapterMatch = text.match(/^第([一二三四五六七八九十]+)章\s+/);
        // 匹配附录模式
        var appendixMatch = text.match(/^附录([一二三四五六七八九十]+)\s+/);

        if (numberMatch || chapterMatch || appendixMatch) {
            var level = 0;
            var number = "";

            if (chapterMatch) {
                level = 1; // 章级别
                number = chapterMatch[1];
            } else if (appendixMatch) {
                level = 1; // 附录级别
                number = "附录" + appendixMatch[1];
            } else if (numberMatch) {
                var numStr = numberMatch[1].trim();
                var parts = numStr.split('.');
                level = parts.length; // 点号数量决定级别
                number = numStr;
            }

            titleStructure.push({
                index: i,
                text: text,
                level: level,
                number: number,
                fullText: text
            });
        }
    }
}

