// 中文数字转换
function getChineseNumber(num) {
    var chineseNumbers = ["一", "二", "三", "四", "五", "六", "七", "八", "九", "十"];
    if (num <= 10) {
        return chineseNumbers[num-1];
    }
    return num.toString();
}

